            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "Naeve",
                text = "So I will ask the question I have been afraid to ask since the sky fell on you and you only nosebled: how many times have you done this? How many margins carry your hand? *(quietly)* Because if you have been here before — if you are the Last Returned's road, walked again — then I am not recruiting a stranger. I am re-reading a book I have read before, and forgotten, and I would very much like to know how it ends.",
