                    new DialogueChoice { text = "\"Then help me make this the time the book ends differently.\"", nextNodeId = "different", effects = new[] { new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 5 } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "remember", speaker = "Naeve",
                text = "*(She folds the page away, slowly.)* This time I remember. *(A long pause.)* Do you know, in three centuries, that is the first new sentence anyone has offered me. Everything else has been an echo. *(She almost smiles.)* Perhaps that is the crack the loop fears, traveller — not your soul's seam, but the chance that someone walks beside you who *remembers the last time.* I will be that someone. Try not to make me read a sad ending again.",
                autoNextNodeId = "done",
                onEnter = new[] { new FlagClause { key = "naeve.remembers_with_you", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 8 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "save", speaker = "Naeve",
                text = "*(The page trembles in her hand.)* ...You wrote the correction to make Karsus *fail.* To make the sky fall a little softer. *(She looks at the ruin of her life's whole world.)* It still fell. But — *(her voice catches, three centuries of grief finding a single crack)* — you *tried.* Across time, before you had a name to forget, you tried to spare us. No one has ever tried to spare Netheril. They only ever mourned it. *(She closes the page like a wound.)* I am yours, traveller. Whatever you are. Whatever you've done before. This time I will help you try.",
                autoNextNodeId = "done",
                onEnter = new[] { new FlagClause { key = "naeve.knows_you_tried", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.recruited", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 12 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "quiet", speaker = "Naeve",
                text = "Some proofs do not resolve, traveller. Perhaps you are one. *(She folds the page away.)* I will walk with you regardless. A flaw in a proof is still the most interesting thing on the page. But know that I am watching the margins now. I have read this book before. I would like, this once, to reach a line I do not recognize.",
                autoNextNodeId = "done",
                onEnter = new[] { new FlagClause { key = "naeve.watching_margins", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "different", speaker = "Naeve",
                text = "*(She studies you for a long moment, then inclines her head — the closest thing she has to a vow.)* Differently. *(She tucks the ancient proof against her heart.)* Three hundred years I have known exactly how every story ends, because I have already read the empire's. *(quietly)* Give me one that surprises me, and I will give you the only thing a dead nation's last daughter still owns: I will remember it. Properly. Out loud. So that this time, the margin is not forgotten.",
