            });

            g.nodes.Add(new DialogueNode
            {
                id = "done", speaker = "Naeve",
                text = "*(She walks on beside you, the ancient proof held to her chest like a relic — which, you suppose, it is.)* The hunter wears your face, and your hand is in my apocalypse's margins, and the loop has no beginning. *(faint, fierce)* And yet I find, against three centuries of evidence, that I am curious how it ends. Lead on, traveller. Let us go and surprise an empire's ghost.",
